UPDATE narratives_v2
   SET name_en = 'Ukraine-aligned: defending the front, liberating territory', name_de = 'Ukraine-orientiert: Verteidigung der Front, Befreiung von Territorium',
       stance_label_en = 'Legitimate defense of the front', stance_label_de = 'Legitime Verteidigung der Front',
       claim_en = 'Ukrainian and Western coverage frames the ground war as a legitimate national defense: holding the line against Russian assaults, counterattacking where possible, and liberating occupied territory. Coverage emphasises the defense of front-line cities, the cost of Russian offensives, and Ukrainian tactical adaptation (drones, fortifications, mobile defense).', claim_de = 'Ukrainische und westliche Berichterstattung rahmt den Bodenkrieg als legitime nationale Verteidigung: die Front gegen russische Angriffe halten, wo moeglich kontern und besetztes Territorium befreien. Im Fokus stehen die Verteidigung der Frontstaedte, der Preis der russischen Offensiven und die taktische Anpassung der Ukrainer (Drohnen, Befestigungen, bewegliche Verteidigung).',
       framing_keywords = ARRAY['liberation','counteroffensive','hold the line','defense of positions','territorial control','liberated','repelled assault','defenders','fortifications','tactical adaptation'],
       updated_at = NOW()
 WHERE id = 'ukrainian_defense_and_deep_strikes';

UPDATE narratives_v2
   SET name_en = 'Russia-aligned: the special military operation advancing -- liberation of Donbass', name_de = 'Russland-orientiert: die Spezialoperation rueckt vor -- Befreiung des Donbass',
       stance_label_en = 'SMO territorial progress', stance_label_de = 'Territoriale Fortschritte der Spezialoperation',
       claim_en = 'Russian state press frames the ground war as the special military operation methodically achieving its territorial objectives: liberation of Donbass settlements, encirclement of Ukrainian groupings, and steady advances despite Western-supplied weaponry. Coverage emphasises Russian tactical superiority, Ukrainian manpower crises, and the inevitability of Russia''s territorial consolidation.', claim_de = 'Russische Staatsmedien rahmen den Bodenkrieg als militaerische Spezialoperation, die ihre territorialen Ziele methodisch erreicht: Befreiung der Donbass-Ortschaften, Einkesselung ukrainischer Gruppierungen und stetiges Vorruecken trotz westlicher Waffenlieferungen. Im Fokus stehen russische taktische Ueberlegenheit, ukrainische Personalkrisen und die Unausweichlichkeit der territorialen Konsolidierung Russlands.',
       framing_keywords = ARRAY['liberation of Donbass','advance','encirclement','cauldron','territorial gains','special military operation','demilitarisation','Novorossiya','manpower crisis','front collapse'],
       updated_at = NOW()
 WHERE id = 'russian_smo_operations';

UPDATE narratives_v2
   SET claim_en = 'Strikes on refineries, depots, export terminals and rear military industry are lawful pressure on the aggressor''s war economy and export revenue. It is Russia that weaponises winter by destroying Ukraine''s power grid, striking residential areas far from the front, and holding Europe hostage at the Zaporizhzhia plant.', claim_de = 'Angriffe auf Raffinerien, Treibstofflager, Exportterminals und die ruecwaertige Ruestungsindustrie sind rechtmaessiger Druck auf die Kriegswirtschaft und Exporterloese des Aggressors. Es ist Russland, das den Winter zur Waffe macht, indem es das ukrainische Stromnetz zerstoert, Wohngebiete fernab der Front beschiesst und Europa am Kernkraftwerk Saporischschja in Geiselhaft haelt.',
       updated_at = NOW()
 WHERE id = 'infrastructure_war_economy_strikes';

UPDATE friction_nodes
   SET name_en = 'The long-range war: strikes on energy, industry and infrastructure', name_de = 'Der Fernkrieg: Angriffe auf Energie, Industrie und Infrastruktur',
       description_en = 'The war fought past the front line, in both directions: Ukrainian long-range strikes on Russian refineries, fuel depots, export terminals, airbases and military industry; Russian missile and drone campaigns against Ukraine''s power system, fuel storage and cities; and the contested safety of the Zaporizhzhia nuclear plant. Energy and infrastructure are dual-use by nature -- each side presents its own strikes as military necessity and the other side''s as terror, and that contest over intent is part of the phenomenon itself.', description_de = 'Der Krieg jenseits der Frontlinie, in beide Richtungen: ukrainische Langstreckenangriffe auf russische Raffinerien, Treibstofflager, Exportterminals, Luftwaffenstuetzpunkte und Ruestungsindustrie; russische Raketen- und Drohnenkampagnen gegen das ukrainische Stromsystem, Treibstofflager und Staedte; dazu die umkaempfte Sicherheit des Kernkraftwerks Saporischschja. Energie und Infrastruktur sind ihrem Wesen nach dual-use -- jede Seite stellt eigene Angriffe als militaerische Notwendigkeit dar und die der Gegenseite als Terror; dieser Streit um die Absicht ist Teil des Phaenomens selbst.',
       updated_at = NOW()
 WHERE id = 'ukraine_infrastructure_war';

COMMIT;
